@namespace Lumeo
@inject IComponentInteropService Interop

@{
    // Visible open item = the intended-open id, but ONLY once a matching item has
    // actually registered. An intent that points at an unregistered id (not yet
    // mounted, or removed) renders as "nothing open" so the Viewport/Indicator
    // never open a blank panel for a non-existent item (round-5 a). It flips back
    // to open automatically when the item (re-)registers.
    var visibleActiveId = _open is not null && _registeredItems.Contains(_open) ? _open : null;
    var context = new NavigationMenuContext(visibleActiveId, EventCallback.Factory.Create<string?>(this, SetActiveItemId), this, DelayDuration);
}

@* aria-label names the navigation landmark so AT users can distinguish it from
   other <nav>s on the page (Radix / APG NavigationMenu contract). *@
<nav class="@CssClass" aria-label="@Label" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</nav>

@code {
    /// <summary>The <see cref="NavigationMenuList"/> (and typically a <see cref="NavigationMenuViewport"/>) that make up the menu.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Accessible name for the &lt;nav&gt; landmark. Defaults to "Main".</summary>
    [Parameter] public string Label { get; set; } = "Main";

    /// <summary>
    /// Controlled value of the currently-open item. Bind with
    /// <c>@bind-Value</c>/<see cref="ValueChanged"/>. The value matches the open
    /// <see cref="NavigationMenuItem.Value"/> (or its auto id when none is set);
    /// <c>null</c> means no submenu is open. Leave unset for uncontrolled use.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Raised when the open item changes (user hover/click/keyboard, or an
    /// item close). Carries the new open item's value, or <c>null</c> when closed.</summary>
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }

    /// <summary>Initial open item for uncontrolled use (ignored once <see cref="Value"/>
    /// is bound). <c>null</c> (default) opens nothing.</summary>
    [Parameter] public string? DefaultValue { get; set; }

    /// <summary>
    /// Grace window in milliseconds before a hovered submenu closes after the
    /// pointer leaves it. Radix's forgiveness delay: moving between adjacent
    /// triggers, or briefly slipping off the panel, does not immediately dismiss.
    /// Defaults to 150ms.
    /// </summary>
    [Parameter] public int DelayDuration { get; set; } = 150;

    /// <summary>Additional CSS classes merged onto the root <c>nav</c> element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root <c>nav</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // ────────────────────────────────────────────────────────────────────────
    // Controlled-value state machine (one coherent design; supersedes the round
    // 2-4 echo-guard / sentinel / _lastValueParam patches).
    //
    // CONTROLLED vs UNCONTROLLED — single definition (`IsControlled`):
    //   controlled  ⇔  ValueChanged.HasDelegate  OR  a non-null Value was EVER
    //                  supplied (_valueEverNonNull latch).
    //   Blazor cannot tell an unset parameter from an explicit null, so a lone
    //   null Value is ambiguous. Convention: treat the menu as controlled the
    //   moment EITHER a change handler is bound (@bind-Value / a listener) OR a
    //   non-null Value is seen — and, once seen, stay controlled (the latch),
    //   mirroring React where `value !== undefined` makes the component
    //   controlled for its whole life. A menu with neither is uncontrolled.
    //
    // INTENT vs VISIBLE:
    //   `_open` is the intended-open id (the state machine's single source of
    //   truth). The VISIBLE open id (exposed on the context, read by Viewport/
    //   Trigger/Indicator/Content) is `_open` gated through `_registeredItems`:
    //   an id with no mounted item shows as closed (computed in the razor block).
    //
    // ADOPTION (parent → machine, in OnParametersSet):
    //   • Seed once: controlled ⇒ _open = Value (verbatim, incl. null = closed;
    //     DefaultValue ignored — Radix). Uncontrolled ⇒ _open = DefaultValue.
    //   • Thereafter, controlled ⇒ adopt Value VERBATIM every parameter set (the
    //     parent is authoritative; there is no echo to guard because interactions
    //     no longer mutate _open in controlled mode). Uncontrolled ⇒ the parent's
    //     Value is not authoritative; _open is owned by interaction.
    //
    // INTERACTION (user → machine, in SetActiveItemId):
    //   • Uncontrolled: mutate _open freely and re-render (optimistic).
    //   • Controlled + handler: emit ValueChanged only; do NOT mutate _open —
    //     render solely what the parent pushes back (a veto = re-render with the
    //     old Value, so nothing to roll back).
    //   • One-way controlled (Value supplied, NO handler): ValueChanged is a
    //     no-op delegate, so the same "emit, don't mutate" path makes interaction
    //     inert — the effective open item cannot change (round-5 b, Radix: a
    //     `value` prop without `onValueChange` is fully controlled).
    //
    // REMOVAL / RE-ADD (item lifecycle → machine):
    //   Registration is (un)registered by NavigationMenuItem. Removing the active
    //   item drops it from _registeredItems, so the VISIBLE id falls to null and
    //   the Viewport closes — but the controlled Value stays authoritative in
    //   _open, so re-registering the item re-opens it automatically. No sentinel.
    //
    // KEYBOARD FOCUS INTENT (_focusContentOnOpenItemId lifecycle):
    //   A trigger's ArrowDown LATCHES this one-shot intent for its item, then emits
    //   the open. Only a KEYBOARD open moves focus INTO the content (Radix); a
    //   programmatic / hover open must not. The intent is resolved where the state
    //   actually settles:
    //     • SET   — trigger.RequestContentFocusOnOpen (ArrowDown), before emitting.
    //     • CONSUME (focus fires) — NavigationMenuContent.OnAfterRenderAsync once the
    //       content for that item has rendered (TryConsumeContentFocusRequest).
    //     • RESOLVE post-render (OnAfterRender), NOT right after
    //       ValueChanged.InvokeAsync. At that earlier point _open still holds the OLD
    //       value (the parent pushes the new Value back through a LATER parameter
    //       set), so an accept could not yet be distinguished from a veto — clearing
    //       there dropped the intent even on an ACCEPTED open and lost the focus
    //       (round-8). It is also NOT sufficient to resolve only in OnParametersSet:
    //       a controlled VETO re-renders the menu with no parameter change (the emit
    //       StateHasChanges this component as the SetActiveItemId receiver), so
    //       OnParametersSet never runs to see it. Once a render settles, _open is
    //       authoritative: intent == _open ⇒ the open was accepted, keep it (the
    //       content will consume it and focus); intent != _open ⇒ veto / one-way /
    //       unrelated render, so drop the stale intent before a LATER parent-
    //       initiated open of that same item can inherit it and steal focus.
    //     • CLEAR on unregistration — a torn-down item can't legitimately receive a
    //       deferred focus (safety; UnregisterItem).
    // ────────────────────────────────────────────────────────────────────────

    // The intended-open item id (source of truth). The visible id is this gated
    // through _registeredItems in the razor block above.
    private string? _open;

    // Latches true once any non-null Value is supplied, making the menu controlled
    // for the rest of its life (see IsControlled).
    private bool _valueEverNonNull;
    private bool _seeded;

    // Currently-mounted item identities (NavigationMenuItem.Value ?? auto id),
    // registered/unregistered by each item. Gates _open → visible so the viewport
    // never opens for an id with no live item.
    private readonly HashSet<string> _registeredItems = new();

    private bool IsControlled => ValueChanged.HasDelegate || _valueEverNonNull;

    protected override void OnParametersSet()
    {
        if (Value is not null) _valueEverNonNull = true;

        if (!_seeded)
        {
            _open = IsControlled ? Value : DefaultValue;
            _seeded = true;
            return;
        }

        // Controlled: the parent owns the open item — adopt Value verbatim each
        // parameter set (including null = closed). Uncontrolled: _open is owned by
        // interaction, so the parent's Value is not consulted here.
        if (IsControlled) _open = Value;
    }

    // Resolve any latched keyboard focus intent AFTER the render settles (see the
    // KEYBOARD FOCUS INTENT block above). This runs post-render rather than in
    // OnParametersSet because a VETO in controlled mode re-renders the menu WITHOUT
    // a parameter change (the emit's StateHasChanged fires on this component as the
    // SetActiveItemId callback receiver, but Value never moves), so OnParametersSet
    // is never entered to observe it. By the time a render completes, _open reflects
    // the settled state: on an ACCEPTED open the adopting OnParametersSet has set
    // _open to the latched item (== intent → keep it; NavigationMenuContent focuses
    // once it renders); on a VETO/one-way/unrelated render _open is still something
    // else (!= intent → drop the stale intent so a LATER parent-initiated open of
    // that same item can't inherit it and steal focus). Clearing a field here does
    // not itself request a re-render, so this cannot loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (_focusContentOnOpenItemId is not null && _focusContentOnOpenItemId != _open)
            _focusContentOnOpenItemId = null;
    }

    // Ordered list of top-level trigger element ids, registered by each
    // NavigationMenuItem so the menu can move focus between them with the arrow
    // keys (roving — APG navigation pattern). Registration follows DOM order
    // because items render top-to-bottom.
    private readonly List<string> _triggerIds = new();

    // When a trigger opens its submenu via the keyboard (ArrowDown), focus must
    // move INTO the content. The trigger can't focus the content synchronously in
    // its keydown handler: SetActiveItemId only schedules the re-render that
    // mounts the content <div>, so the element doesn't exist in the DOM yet and
    // the focus call is silently dropped in a real browser. Instead the trigger
    // records a one-shot request here, and NavigationMenuContent consumes it from
    // its own OnAfterRenderAsync — i.e. AFTER the content has actually rendered.
    private string? _focusContentOnOpenItemId;

    private string CssClass => Cx.Merge("relative z-10 flex max-w-max flex-1 items-center justify-center", Class);

    private async Task SetActiveItemId(string? value)
    {
        if (IsControlled)
        {
            // Controlled: report intent and let the parent decide by pushing Value
            // back. Do NOT touch _open — the render reflects only what the parent
            // adopts. With a one-way Value (no ValueChanged delegate) the invoke is
            // a no-op, so interaction is inert (fully controlled — round-5 b).
            //
            // Do NOT resolve the keyboard focus intent here: _open still holds the
            // OLD value at this point (the parent pushes the accepted Value back
            // through a LATER OnParametersSet), so `_open != value` is true even on
            // an ACCEPTED open — clearing here dropped the intent and lost the focus
            // (round-8). The intent is resolved at ADOPTION time in OnParametersSet
            // instead, where an accept and a veto are actually distinguishable.
            await ValueChanged.InvokeAsync(value);
        }
        else
        {
            // Uncontrolled: we own the open item — mutate optimistically and render.
            _open = value;
            StateHasChanged();
        }
    }

    // Called by a trigger when it opens its submenu via the keyboard. The focus
    // request is deferred until the matching content has rendered (consumed in
    // NavigationMenuContent.OnAfterRenderAsync) so focus lands on a live element.
    internal void RequestContentFocusOnOpen(string itemId) => _focusContentOnOpenItemId = itemId;

    // Returns true (and clears the one-shot request) when the just-rendered
    // content belongs to the item whose submenu was opened from the keyboard.
    internal bool TryConsumeContentFocusRequest(string itemId)
    {
        if (_focusContentOnOpenItemId != itemId) return false;
        _focusContentOnOpenItemId = null;
        return true;
    }

    internal void RegisterTrigger(string id)
    {
        if (!_triggerIds.Contains(id)) _triggerIds.Add(id);
    }

    internal void UnregisterTrigger(string id) => _triggerIds.Remove(id);

    // Item-identity registration (NavigationMenuItem.Value ?? auto id), tracked
    // separately from the trigger-id roving list. Gates _open → visible so the
    // Viewport/Indicator never open for an id with no mounted item. When the
    // (un)registered id is the intended-open one, the visible state changes, so we
    // re-render: registering re-opens a pending/re-added active item, unregistering
    // closes the viewport on the torn-down active item — while _open (the
    // controlled intent) stays authoritative and re-applies on the next register.
    internal void RegisterItem(string id)
    {
        if (_registeredItems.Add(id) && id == _open) StateHasChanged();
    }

    internal void UnregisterItem(string id)
    {
        // Safety: an item being torn down can never legitimately receive a deferred
        // focus-into-content request, so drop any intent latched for it to avoid a
        // stale request outliving the item and firing on a later re-add.
        if (_focusContentOnOpenItemId == id) _focusContentOnOpenItemId = null;
        if (_registeredItems.Remove(id) && id == _open) StateHasChanged();
    }

    // Move focus to the trigger `delta` positions from `currentId` (wrapping).
    // Used by NavigationMenuTrigger's ArrowLeft/ArrowRight handlers.
    internal async Task FocusTriggerRelative(string currentId, int delta)
    {
        if (_triggerIds.Count == 0) return;
        var index = _triggerIds.IndexOf(currentId);
        if (index < 0) return;
        var next = ((index + delta) % _triggerIds.Count + _triggerIds.Count) % _triggerIds.Count;
        try { await Interop.FocusElement(_triggerIds[next]); } catch (JSDisconnectedException) { }
    }

    internal async Task FocusTriggerEdge(bool last)
    {
        if (_triggerIds.Count == 0) return;
        try { await Interop.FocusElement(last ? _triggerIds[^1] : _triggerIds[0]); }
        catch (JSDisconnectedException) { }
    }

    public record NavigationMenuContext(string? ActiveItemId, EventCallback<string?> SetActiveItemId, NavigationMenu Owner, int CloseDelayMs);
}

@namespace Lumeo
@implements IAsyncDisposable
@implements IOverlayExitCallback

@if (_exit.Present(IsOpen))
{
    <div id="@_contentId" role="menu" aria-labelledby="@ItemContext.TriggerId" data-state="@(IsOpen ? "open" : "closed")" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
        <div class="@InnerCssClass">
            @ChildContent
        </div>
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    [CascadingParameter] public NavigationMenuItem.NavigationMenuItemContext ItemContext { get; set; } = default!;
    /// <summary>The submenu panel content shown when the owning <see cref="NavigationMenuItem"/> is open.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the root panel element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root panel element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id from the item context so the trigger's aria-controls
    // points here and ArrowDown on the trigger can focus this element.
    private string _contentId => ItemContext.ContentId;
    private bool _registered;

    // B11 exit latch (shared infra). Enter keeps fade-in; the submenu panel is wide,
    // so exit mirrors it with a symmetric fade-out rather than a zoom.
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<NavigationMenuContent>? _selfRef;
    private const int ExitDurationMs = 250;

    private bool IsOpen => Context.ActiveItemId == ItemContext.ItemId;

    // pointer-events-none blocks the pointer on the fading panel; `inert` (rendered
    // only during the exit window) additionally removes its native links/buttons from
    // the tab order + a11y tree so keyboard users can't Tab into a visually-closed
    // submenu while it animates out (round-1 added neither here — P2). Focus already
    // left on close (Escape returns it to the trigger), so inert traps nothing.
    private string AnimationClass => _exit.Exiting ? "animate-fade-out pointer-events-none" : "animate-fade-in";
    private string? ExitInert => _exit.Exiting ? "true" : null;

    private string CssClass => Cx.Merge("fixed z-50", AnimationClass, Class);

    private string InnerCssClass => "mt-1.5 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover p-4 text-popover-foreground shadow-lg";

    protected override void OnParametersSet()
        => _exit.OnParameters(IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.ActiveItemId == ItemContext.ItemId && !_registered)
        {
            await Interop.PositionFixed(_contentId, ItemContext.TriggerId, "start");
            await Interop.RegisterClickOutside(_contentId, ItemContext.TriggerId, async () =>
            {
                await Context.SetActiveItemId.InvokeAsync(null);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;

            // If this submenu was opened from the keyboard (ArrowDown on the
            // trigger), move focus INTO the content now that it has actually
            // rendered. The trigger can't focus it synchronously — the element
            // didn't exist yet when its keydown handler ran (mirrors
            // MenubarContent's focus-into-content on the open transition).
            if (Context.Owner.TryConsumeContentFocusRequest(ItemContext.ItemId))
            {
                try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
            }
        }
        else if (Context.ActiveItemId != ItemContext.ItemId && _registered)
        {
            // Cleanup runs immediately on close (stops the reposition rAF, leaves the
            // inline top/left so the box freezes while the fade-out plays).
            await Cleanup();
        }

        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        });
    }

    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish()) StateHasChanged();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await Context.SetActiveItemId.InvokeAsync(null);
            // Return focus to the trigger so the user isn't stranded.
            try { await Interop.FocusElement(ItemContext.TriggerId); } catch (JSDisconnectedException) { }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        if (_registered) await Cleanup();
    }
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<button type="button" class="@CssClass" @onclick="Toggle" aria-label="@L["Navigation.Toggle"]" @attributes="AdditionalAttributes">
    <SvgGlyph Svg="@(LumeoIcons.Menu)" class="h-5 w-5" />
</button>

@code {
    /// <summary>Whether the mobile menu this hamburger controls is open. Pair with <see cref="OpenChanged"/> for two-way binding.</summary>
    [Parameter] public bool Open { get; set; }

    /// <summary>Raised when the button is clicked and toggles <see cref="Open"/>.</summary>
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>Obsolete alias for <see cref="Open"/>.</summary>
    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    /// <summary>Obsolete alias for <see cref="OpenChanged"/>.</summary>
    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    /// <summary>Additional CSS classes merged onto the root button element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root button element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center rounded-md p-2 hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2 md:hidden", Class);

    private async Task Toggle()
    {
        Open = !Open;
        await OpenChanged.InvokeAsync(Open);
    }
}

