@namespace Lumeo
@implements IDisposable

@{
    var itemContext = new NavigationMenuItemContext(ItemIdentity, _triggerId, _contentId);
}

@* Non-fixed cascade (mirrors the parent NavigationMenuContext): ItemIdentity derives
   from the mutable Value parameter, so a fixed cascade would leave descendants (Trigger/
   Content) matching a STALE ItemId if Value changed while the item stayed mounted. The
   record is value-equal across unrelated renders, so descendants only re-render when the
   identity actually changes (Codex round-3 P2). *@
<CascadingValue Value="itemContext" IsFixed="false">
    <li class="@CssClass"
        @onpointerenter="HandlePointerEnter"
        @onpointerleave="HandlePointerLeave"
        @attributes="AdditionalAttributes">
        @ChildContent
    </li>
</CascadingValue>

@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    /// <summary>Typically a <see cref="NavigationMenuTrigger"/> plus <see cref="NavigationMenuContent"/>, or a plain <see cref="NavigationMenuLink"/> for a leaf item.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Stable identity for this item, used by the controlled
    /// <see cref="NavigationMenu.Value"/> binding to say which item is open. When
    /// unset an auto id is used, so uncontrolled menus keep working unchanged.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Additional CSS classes merged onto the root <c>li</c> element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root <c>li</c> element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("nav-item");
    private readonly string _triggerId = LumeoIds.New("nav-trigger");
    // Stable content id shared with the trigger (aria-controls) and the content
    // (focus-into target).
    private readonly string _contentId = LumeoIds.New("nav-content");
    private readonly DelayedDispatch _dispatch = new();

    // Consumer-supplied Value takes precedence so a controlled NavigationMenu can
    // address this item; otherwise fall back to the auto id.
    private string ItemIdentity => Value ?? _itemId;

    // The identity currently registered with the menu; tracked so a Value change
    // while the item stays mounted swaps the registration (old id out, new id in)
    // rather than leaking a stale entry.
    private string? _registeredIdentity;

    private string CssClass => Cx.Merge("relative", Class);

    // Register this item's trigger id with the menu so arrow-key roving can move
    // focus between top-level triggers in DOM order.
    protected override void OnInitialized() => Context.Owner.RegisterTrigger(_triggerId);

    // Register this item's identity so the menu can gate its intended-open id
    // (NavigationMenu._open) to only ids with a live item — the viewport never
    // opens a blank panel for an unmounted/removed id, and a controlled Value
    // pointing here re-opens the moment this registers. Re-runs on every parameter
    // set; a changed Value swaps the registration.
    protected override void OnParametersSet()
    {
        var identity = ItemIdentity;
        if (_registeredIdentity == identity) return;
        if (_registeredIdentity is not null) Context.Owner.UnregisterItem(_registeredIdentity);
        Context.Owner.RegisterItem(identity);
        _registeredIdentity = identity;
    }

    // rc.44 — Approach B: pointer events with PointerType filter. On touch
    // devices the browser emulates `mouseenter` on tap and `mouseleave` when
    // the finger lifts — closing the submenu before the user can interact
    // with it. Only fire hover behavior for mouse pointers; touch users rely
    // on the explicit @onclick toggle in NavigationMenuTrigger.
    private void HandlePointerEnter(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        _dispatch.Cancel();
    }

    private void HandlePointerLeave(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        if (Context.ActiveItemId == ItemIdentity)
        {
            // Grace window (Context.CloseDelayMs): moving to an adjacent trigger
            // re-opens on that trigger's pointerenter before this fires, and this
            // scheduled close then no-ops because ActiveItemId no longer matches.
            _dispatch.Schedule(Context.CloseDelayMs, () => InvokeAsync(async () =>
            {
                if (Context.ActiveItemId == ItemIdentity)
                {
                    await Context.SetActiveItemId.InvokeAsync(null);
                    StateHasChanged();
                }
            }));
        }
    }

    public void Dispose()
    {
        _dispatch.Dispose();
        Context.Owner.UnregisterTrigger(_triggerId);
        // Drop this item's identity registration. If it was the intended-open id,
        // the menu's visible state falls to null so the Viewport/Indicator close
        // instead of staying stuck open on a removed item — while a controlled
        // Value still pointing here re-opens automatically if the item re-mounts.
        if (_registeredIdentity is not null) Context.Owner.UnregisterItem(_registeredIdentity);
    }

    public record NavigationMenuItemContext(string ItemId, string TriggerId, string ContentId);
}

@namespace Lumeo

<a href="@Href" class="@CssClass" aria-current="@(IsActive ? "page" : null)" @onclick="HandleClick" @attributes="AdditionalAttributes">
    @ChildContent
</a>

@code {
