@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    [CascadingParameter] public NavigationMenuItem.NavigationMenuItemContext ItemContext { get; set; } = default!;
    /// <summary>The trigger's label content, rendered before the chevron indicator.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the root button element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the root button element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsActive => Context.ActiveItemId == ItemContext.ItemId;

    private string CssClass => Cx.Merge(
        "group inline-flex h-9 w-max items-center justify-center rounded-md bg-background px-4 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground focus:outline-none disabled:pointer-events-none disabled:opacity-50",
        Cx.When(IsActive, "bg-accent/50"),
        Class);

    private string ChevronClasses => Cx.Join(
        "relative top-[1px] ms-1 h-3 w-3 transition-transform duration-200",
        Cx.When(IsActive, "rotate-180"));

    private async Task HandleClick()
    {
        if (IsActive)
        {
            await Context.SetActiveItemId.InvokeAsync(null);
        }
        else
        {
            await Context.SetActiveItemId.InvokeAsync(ItemContext.ItemId);
        }
    }

    // rc.44 — only auto-open for mouse pointers. On touch devices the browser
    // emulates pointerenter on tap; combined with the parent's hover-leave on
    // finger-lift, this would briefly flash the submenu before closing it.
    // Touch users open via @onclick.
    private async Task HandlePointerEnter(PointerEventArgs e)
    {
        if (e.PointerType != "mouse") return;
        await Context.SetActiveItemId.InvokeAsync(ItemContext.ItemId);
    }

    // APG navigation keyboard model: Left/Right move focus between top-level
    // triggers (roving), Home/End jump to the first/last, ArrowDown (or
    // Enter/Space — handled natively by the button click) opens this item and
    // moves focus into its content, Escape closes the open item.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowRight":
                await Context.Owner.FocusTriggerRelative(ItemContext.TriggerId, 1);
                break;
            case "ArrowLeft":
                await Context.Owner.FocusTriggerRelative(ItemContext.TriggerId, -1);
                break;
            case "Home":
                await Context.Owner.FocusTriggerEdge(last: false);
                break;
            case "End":
                await Context.Owner.FocusTriggerEdge(last: true);
                break;
            case "ArrowDown":
                // Open this item and ask its content to grab focus AFTER it
                // renders. Focusing ItemContext.ContentId synchronously here would
                // target an element that SetActiveItemId has only scheduled to
                // mount — it isn't in the DOM yet, so the focus call is silently
                // dropped in a real browser. NavigationMenuContent consumes this
                // one-shot request from its own OnAfterRenderAsync instead.
                Context.Owner.RequestContentFocusOnOpen(ItemContext.ItemId);
                if (!IsActive) await Context.SetActiveItemId.InvokeAsync(ItemContext.ItemId);
                break;
            case "Escape":
                if (IsActive) await Context.SetActiveItemId.InvokeAsync(null);
                break;
        }
    }
}

@namespace Lumeo
@implements IAsyncDisposable
@implements IOverlayExitCallback
@inject IComponentInteropService Interop

@if (_exit.Present(IsOpen))
{
    <div class="@CssClass" data-state="@(IsOpen ? "open" : "closed")" inert="@ExitInert" @attributes="AdditionalAttributes">
        <div id="@_viewportId" class="@InnerCssClass">
            @ChildContent
        </div>
    </div>
}

@code {
    [CascadingParameter] public NavigationMenu.NavigationMenuContext Context { get; set; } = default!;
    /// <summary>Optional content rendered inside the viewport frame while any menu item is open.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Additional CSS classes merged onto the outer positioning wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the outer positioning wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _viewportId = LumeoIds.New("nav-viewport");

    // B11 exit latch (shared infra). The viewport fades its content in on open, so
    // the exit mirrors it with a symmetric fade-out kept mounted through the window.
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<NavigationMenuViewport>? _selfRef;
    private const int ExitDurationMs = 250;

    private bool IsOpen => Context.ActiveItemId is not null;

    private string CssClass => Cx.Merge("absolute start-0 top-full flex justify-center", Class);

    // The animate-* class lives on the inner (id'd) element so attachOverlayExitEnd
    // samples the right node. pointer-events-none keeps the fading panel from taking
    // clicks; `inert` on the outer wrapper (exit window only) also drops its focusable
    // content from the tab order so keyboard users can't Tab into a closing panel (P2).
    private string AnimationClass => _exit.Exiting ? "animate-fade-out pointer-events-none" : "animate-fade-in";
    private string? ExitInert => _exit.Exiting ? "true" : null;

    // Height is content-driven (h-auto). Radix's Viewport sizes with
    // h-[var(--radix-navigation-menu-viewport-height)], a var its JS sets by
    // measuring the active portaled panel to drive the height-resize animation.
    // This library positions each NavigationMenuContent as its own fixed panel
    // (no shared viewport portal), so nothing ever set that var — the height then
    // resolved to `auto` only by the invalid-var fallback (verified in-browser:
    // the box did NOT collapse to 0, it took content height). Depending on that
    // accident was fragile and advertised a resize animation that never ran, so
    // the dead var is dropped and the panel sizes to its content explicitly.
    private string InnerCssClass => Cx.Merge("origin-top-center relative mt-1.5 h-auto w-full overflow-hidden rounded-md border border-border/40 bg-popover text-popover-foreground shadow-lg", AnimationClass);

    protected override void OnParametersSet()
        => _exit.OnParameters(IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_viewportId, _selfRef); }
            catch (JSDisconnectedException) { }
        });
    }

    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish()) StateHasChanged();
    }

    public ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        return ValueTask.CompletedTask;
    }
}
